function lengthOfLongestSubstring(s) {
  const inWin = new Set();
  let l = 0, best = 0;
  for (let r = 0; r < s.length; r++) {
    while (inWin.has(s[r])) { inWin.delete(s[l]); l++; }
    inWin.add(s[r]);
    best = Math.max(best, r - l + 1);
  }
  return best;
}

