exercises.solution:
function evalRPN(tokens) {
  const st = [];
  for (const t of tokens) {
    if (t === '+' || t === '-' || t === '*' || t === '/') {
      const b = st.pop(), a = st.pop();
      let v;
      if (t === '+') v = a + b;
      else if (t === '-') v = a - b;
      else if (t === '*') v = a * b;
      else v = Math.trunc(a / b);
      st.push(v);
    } else st.push(Number(t));
  }
  return st[0];
}

