function dailyTemperatures(temps) {
  const res = Array(temps.length).fill(0);
  const st = [];
  for (let i = 0; i < temps.length; i++) {
    while (st.length && temps[i] > temps[st[st.length - 1]]) {
      const j = st.pop();
      res[j] = i - j;
    }
    st.push(i);
  }
  return res;
}

