exercises.solution:
function numIslands(grid) {
  const R = grid.length, C = grid[0].length;
  function sink(r, c) {
    if (r < 0 || c < 0 || r >= R || c >= C || grid[r][c] !== '1') return;
    grid[r][c] = '0';
    sink(r+1, c); sink(r-1, c); sink(r, c+1); sink(r, c-1);
  }
  let count = 0;
  for (let r = 0; r < R; r++)
    for (let c = 0; c < C; c++)
      if (grid[r][c] === '1') { count++; sink(r, c); }
  return count;
}

