exercises.solution:
function kClosest(points, k) {
  // max-heap of size k via negated squared distance on an array-backed heap
  const a = []; // entries: [negDist, point]
  const push = (e) => {
    a.push(e);
    let i = a.length - 1;
    while (i > 0) {
      const p = (i - 1) >> 1;
      if (a[p][0] <= a[i][0]) break;
      [a[p], a[i]] = [a[i], a[p]]; i = p;
    }
  };
  const pop = () => {
    const top = a[0], last = a.pop();
    if (a.length) {
      a[0] = last;
      let i = 0;
      while (true) {
        const l = 2*i+1, r = 2*i+2; let m = i;
        if (l < a.length && a[l][0] < a[m][0]) m = l;
        if (r < a.length && a[r][0] < a[m][0]) m = r;
        if (m === i) break;
        [a[m], a[i]] = [a[i], a[m]]; i = m;
      }
    }
    return top;
  };
  for (const p of points) {
    push([-(p[0]*p[0] + p[1]*p[1]), p]);
    if (a.length > k) pop();
  }
  return a.map(e => e[1]);
}

