function combinationSum(candidates, target) {
  const cand = candidates.slice().sort((a, b) => a - b);
  const res = [], path = [];
  function dfs(start, remaining) {
    if (remaining === 0) { res.push([...path]); return; }
    for (let i = start; i < cand.length; i++) {
      if (cand[i] > remaining) break;
      path.push(cand[i]);
      dfs(i, remaining - cand[i]);
      path.pop();
    }
  }
  dfs(0, target);
  return res;
}

